import React, { useEffect, useState, useMemo } from "react";
import { useNavigate } from "react-router-dom"; // Add this import
import {
  Card,
  Spin,
  Typography,
  DatePicker,
  Button,
  message,
  Space,
  Input,
  Row,
  Col,
  Select,
  Empty,
  Tag,
} from "antd";
import {
  UserOutlined,
  FileExcelOutlined,
  TeamOutlined,
  ApartmentOutlined,
  CalendarTwoTone,
  ScheduleOutlined,
  ClockCircleOutlined,
  CalendarOutlined,
} from "@ant-design/icons";
import axiosInstance from "../../../core/config/axiosInstance";
import * as XLSX from "xlsx";
import { saveAs } from "file-saver";
import dayjs from "dayjs";
import BASE_URL from "../../../core/config/Config";
import TaskAdminPanelLayout from "../components/TaskAdminPanelLayout";
import useAuth from "../../../shared/hooks/useAuth";

const { Title, Text } = Typography;
const { Search } = Input;
const { Option } = Select;

const TEAM_OPTIONS = [
  "ALL",
  "TECHTEAM",
  "ADMINTEAM",
  "HRTEAM",
  "TELECALLINGTEAM",
  "ACCOUNTINGTEAM",
  "SALESTEAM",
  "MANAGEMENTTEAM",
];

const labelStyle = {
  fontWeight: 550,
  fontSize: 14,
  color: "#555",
  minWidth: 130,
  display: "inline-block",
};

const valueStyle = {
  fontWeight: 700,
  fontSize: 12,
  color: "#111",
};

const iconStyle = { fontSize: 20, color: "#1890ff", marginRight: 8 };
const metricRowStyle = {
  display: "flex",
  alignItems: "center",
  gap: 8,
  lineHeight: 1.8,
};
const metricValueStyle = {
  ...valueStyle,
  marginLeft: "auto",
  textAlign: "right",
  wordBreak: "break-word",
};

const formatTeamLabel = (team) =>
  team === "ALL"
    ? "All Teams"
    : team
        .replace(/TEAM$/i, " Team")
        .replace(/([A-Z]+)([A-Z][a-z])/g, "$1 $2")
        .replace(/([a-z])([A-Z])/g, "$1 $2");

const TeamAttendanceReport = () => {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedMonth, setSelectedMonth] = useState(dayjs());
  const [searchText, setSearchText] = useState("");
  const [selectedTeam, setSelectedTeam] = useState("ALL");
  const navigate = useNavigate(); // Initialize useNavigate
  const fetchAttendanceData = async (month) => {
    try {
      setLoading(true);
      const response = await axiosInstance.get(
        `${BASE_URL}/user-service/write/team_attendance_report?month=${month}`,
      );
      setData(response.data || []);
    } catch (error) {
      message.error("Failed to fetch attendance data.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAttendanceData(selectedMonth.format("YYYY-MM"));
  }, [selectedMonth]);

  const handleMonthChange = (date) => {
    if (date) {
      setSelectedMonth(date);
      fetchAttendanceData(date.format("YYYY-MM"));
    }
  };

  const exportToExcel = () => {
    const users = filteredData; // include all users
    if (users.length === 0) {
      message.warning("No data to export.");
      return;
    }

    const formattedData = users.map((user) => ({
      Name: user.name,
      Department: user.department,
      "Leave Days": user.leaveDaysInMonth,
      "POD Updates": user.podUpdateReport,
      "EOD Updates": user.eodUpdationEntries,
      "EMP Working Days": user.employeeWorkingDays,
      "Avg Per Day Spent Hours": user.avgPerDaySpentHours,
      "Monthly Spend Hours": user.employeeMonthlySpentHours,
    }));

    const worksheet = XLSX.utils.json_to_sheet(formattedData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Attendance");

    const buffer = XLSX.write(workbook, { bookType: "xlsx", type: "array" });
    const blob = new Blob([buffer], { type: "application/octet-stream" });

    saveAs(blob, `Team_Attendance_${selectedMonth.format("YYYY-MM")}.xlsx`);
  };

  const filteredData = useMemo(() => {
    return data
      .filter((user) =>
        selectedTeam === "ALL"
          ? true
          : user.department?.toUpperCase() === selectedTeam,
      )
      .filter((user) =>
        user.name?.toLowerCase().includes(searchText.toLowerCase()),
      )
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [data, selectedTeam, searchText]);

  const summaryCards = [
    {
      label: "Working Days",
      value: filteredData[0]?.workingDays ?? "N/A",
      icon: <CalendarOutlined style={{ fontSize: 30, color: "#1890ff" }} />,
      bgColor: "#e6f7ff",
    },
    {
      label: "Public Holidays",
      value: filteredData[0]?.publicHoliday ?? "N/A",
      icon: <CalendarOutlined style={{ fontSize: 30, color: "#cf1322" }} />,
      bgColor: "#fff1f0",
    },
    {
      label: "Total Month Days",
      value: filteredData[0]?.monthDays ?? "N/A",
      icon: <CalendarOutlined style={{ fontSize: 30, color: "#389e0d" }} />,
      bgColor: "#f6ffed",
    },
    {
      label: "Sundays",
      value: filteredData[0]?.sundayCount ?? "N/A",
      icon: <CalendarOutlined style={{ fontSize: 30, color: "#faad14" }} />,
      bgColor: "#fffbe6",
    },
    {
      label: "Monthly Working Hrs",
      value: filteredData[0]?.monthlyWorkingHours ?? "",
      icon: <CalendarOutlined style={{ fontSize: 30, color: "#722ed1" }} />,
      bgColor: "#f9f0ff",
    },
    {
      label: "Total Employees",
      value: filteredData[0]?.totalEmpCount ?? "",
      icon: <CalendarOutlined style={{ fontSize: 30, color: "#13c2c2" }} />,
      bgColor: "#e6fffb",
    },
  ];

  return (
    <TaskAdminPanelLayout>
      <Card
        title={
          <Space>
            <TeamOutlined />
            <Title level={4} style={{ margin: 0 }}>
              Team Attendance Report
            </Title>
          </Space>
        }
        extra={
          <Space wrap size={10}>
            {/* <Tag color="blue" style={{ borderRadius: 16, marginInlineEnd: 0 }}>
              {filteredData.length} Employees
            </Tag> */}
            <Select
              value={selectedTeam}
              onChange={(value) => setSelectedTeam(value)}
              style={{ width: 210 }}
              showSearch
              optionFilterProp="children"
            >
              {TEAM_OPTIONS.map((team) => (
                <Option key={team} value={team}>
                  {formatTeamLabel(team)}
                </Option>
              ))}
            </Select>
            <DatePicker
              picker="month"
              value={selectedMonth}
              onChange={handleMonthChange}
              allowClear={false}
            />
            <Button
              icon={<FileExcelOutlined />}
              style={{
                backgroundColor: "#008cba",
                borderColor: "#008cba",
                color: "#fff",
              }}
              onClick={exportToExcel}
            >
              Download Excel
            </Button>
          </Space>
        }
        style={{ margin: 20, borderRadius: 10 }}
        bodyStyle={{ paddingTop: 20 }}
      >
        {/* Summary Cards */}
        {!loading && filteredData.length > 0 && (
          <Row gutter={[24, 24]} justify="start" style={{ marginBottom: 30 }}>
            {summaryCards.map((item, index) => (
              <Col key={index} xs={24} sm={12} md={8} lg={4}>
                <Card
                  bordered={false}
                  style={{
                    borderRadius: 10,
                    background: item.bgColor,
                    textAlign: "center",
                    boxShadow: "0 4px 14px rgba(0,0,0,0.08)",
                    height: "100%",
                  }}
                >
                  <div style={{ marginBottom: 8 }}>{item.icon}</div>
                  <Text type="secondary" style={{ fontSize: 14 }}>
                    {item.label}
                  </Text>
                  <br />
                  <Text strong style={{ fontSize: 18, color: "#111" }}>
                    {item.value}
                  </Text>
                </Card>
              </Col>
            ))}
          </Row>
        )}

        <Search
          placeholder="Search employee by name"
          allowClear
          onChange={(e) => setSearchText(e.target.value)}
          style={{ marginBottom: 20, maxWidth: 360 }}
        />

        {loading ? (
          <div
            style={{
              display: "flex",
              justifyContent: "center",
              alignItems: "center",
              minHeight: 200,
            }}
          >
            <Spin size="medium" />
          </div>
        ) : filteredData.length === 0 ? (
          <Card
            bordered={false}
            style={{
              borderRadius: 12,
              background: "#fafafa",
              textAlign: "center",
            }}
            bodyStyle={{ padding: "30px 16px" }}
          >
            <Empty
              image={Empty.PRESENTED_IMAGE_SIMPLE}
              description={
                <span>
                  No attendance data found for this filter.
                  <br />
                  Try another team, month, or clear search text.
                </span>
              }
            />
          </Card>
        ) : (
          <Row gutter={[24, 24]} justify="start">
            {filteredData.map((user) => (
              <Col
                key={user.userid}
                xs={24}
                sm={12}
                lg={8}
                style={{ display: "flex" }}
              >
                <Card
                  title={
                    <Space>
                      <UserOutlined
                        style={{ fontSize: 20, color: "#1890ff" }}
                      />
                      <Text strong style={{ fontSize: 14, color: "#0c5484" }}>
                        {user.name}
                      </Text>
                    </Space>
                  }
                  style={{
                    borderRadius: 10,
                    boxShadow: "0 4px 14px rgba(0,0,0,0.08)",
                    width: "100%",
                    transition: "transform 0.2s ease-in-out",
                    cursor: "pointer",
                  }}
                  bodyStyle={{ padding: 16 }}
                  hoverable
                  onClick={() =>
                    navigate(
                      `/taskmanagement/user-task-details/${user.userid}`,
                      {
                        state: {
                          selectedMonth: selectedMonth.format("YYYY-MM"),
                        },
                      },
                    )
                  }
                >
                  <div>
                    <div style={metricRowStyle}>
                      <ApartmentOutlined style={iconStyle} />
                      <span style={labelStyle}>Department:</span>
                      <span style={metricValueStyle}>
                        {user.department || "-"}
                      </span>
                    </div>
                    <div style={metricRowStyle}>
                      <CalendarTwoTone
                        twoToneColor="#eb2f96"
                        style={iconStyle}
                      />
                      <span style={labelStyle}>Leave Days:</span>
                      <span style={metricValueStyle}>
                        {user.leaveDaysInMonth}
                      </span>
                    </div>
                    <div style={metricRowStyle}>
                      <UserOutlined style={iconStyle} />
                      <span style={labelStyle}>POD Updates:</span>
                      <span style={metricValueStyle}>
                        {user.podUpdateReport}
                      </span>
                    </div>
                    <div style={metricRowStyle}>
                      <UserOutlined style={iconStyle} />
                      <span style={labelStyle}>EOD Updates:</span>
                      <span style={metricValueStyle}>
                        {user.eodUpdationEntries}
                      </span>
                    </div>
                    <div style={metricRowStyle}>
                      <UserOutlined style={iconStyle} />
                      <span style={labelStyle}>EOD Missing:</span>
                      <span style={metricValueStyle}>
                        {user.eodMissingEntries}
                      </span>
                    </div>
                    <div style={metricRowStyle}>
                      <UserOutlined style={iconStyle} />
                      <span style={labelStyle}>EMP Working Days:</span>
                      <span style={metricValueStyle}>
                        {user.employeeWorkingDays}
                      </span>
                    </div>
                    <div style={metricRowStyle}>
                      <ClockCircleOutlined style={iconStyle} />
                      <span style={labelStyle}>Avg/Day Hrs Spent:</span>
                      <span style={metricValueStyle}>
                        {user.avgPerDaySpentHours}
                      </span>
                    </div>
                    <div style={metricRowStyle}>
                      <ScheduleOutlined style={iconStyle} />
                      <span style={labelStyle}>Monthly Hrs Spent:</span>
                      <span style={metricValueStyle}>
                        {user.employeeMonthlySpentHours}
                      </span>
                    </div>
                  </div>
                </Card>
              </Col>
            ))}
          </Row>
        )}
      </Card>
    </TaskAdminPanelLayout>
  );
};

export default TeamAttendanceReport;
